  loadPayslip() {
    const emp = this.currentEmp;
    if (!emp) return;
    const monthly = emp.ctc / 12;
    const basic = monthly * 0.5;
    const hra = monthly * 0.20;
    const da = monthly * 0.05;
    const special = monthly * 0.15;
    const gross = basic + hra + da + special;
    const pf = basic * 0.12;
    const pt = 200;
    const tds = gross * 0.08;
    const net = Math.round(gross - pf - pt - tds);
    const m = this.months[this.selectedMonthIdx];
    this.slip = {
      monthLabel: m.label.split(' ')[0],
      year: m.label.split(' ')[1],
      daysWorked: 26,
      earnings: [{
        label: 'Basic Salary',
        amount: Math.round(basic)
      }, {
        label: 'House Rent Allowance',
        amount: Math.round(hra)
      }, {
        label: 'Dearness Allowance',
        amount: Math.round(da)
      }, {
        label: 'Special Allowance',
        amount: Math.round(special)
      }],
      deductions: [{
        label: 'Provident Fund',
        amount: Math.round(pf)
      }, {
        label: 'Professional Tax',
        amount: pt
      }, {
        label: 'Tax Deducted at Source',
        amount: Math.round(tds)
      }],
      gross: Math.round(gross),
      totalDeductions: Math.round(pf + pt + tds),
      netPay: net,
      netInWords: 'Rupees One Lakh Five Thousand Fifty Only'
    };
  }
